package com.cho2hand.marketplace.entity.media;
import jakarta.persistence.*; import java.time.Instant;
@Entity @Table(name="media_assets") public class MediaAsset { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="media_id") private Long id; @Column(name="owner_user_id",nullable=false) private Long ownerUserId; @Column(name="storage_key",nullable=false) private String storageKey; @Column(name="content_type",nullable=false) private String contentType; @Column(name="byte_size",nullable=false) private long byteSize; @Lob @Column(name="storage_data",columnDefinition="LONGBLOB") private byte[] storageData; @Column(name="created_at",nullable=false) private Instant createdAt; @PrePersist void created(){createdAt=Instant.now();} public Long getId(){return id;} public Long getOwnerUserId(){return ownerUserId;} public void setOwnerUserId(Long v){ownerUserId=v;} public String getStorageKey(){return storageKey;} public void setStorageKey(String v){storageKey=v;} public String getContentType(){return contentType;} public void setContentType(String v){contentType=v;} public long getByteSize(){return byteSize;} public void setByteSize(long v){byteSize=v;} public byte[] getStorageData(){return storageData;} public void setStorageData(byte[] v){storageData=v;} }
